const ASMA = [
  {n:1,ar:'الرَّحْمَنُ',en:'Ar-Rahman',desc:'الذي وسعت رحمته جميع خلقه في الدنيا، فلا يظلم أحدٌ رحمته شيئاً، وهو الذي يرحم المؤمنين والكافرين في رزقهم وحياتهم'},
  {n:2,ar:'الرَّحِيمُ',en:'Ar-Rahim',desc:'الذي يُخص المؤمنين برحمته في الآخرة، كما قال تعالى: ﴿وَكَانَ بِالْمُؤْمِنِينَ رَحِيمًا﴾'},
  {n:3,ar:'الْمَلِكُ',en:'Al-Malik',desc:'صاحب الملك والسلطان المطلق، الذي يملك كل شيء ولا يملك شيءٌ غيره، ومنه ملكه العباد'},
  {n:4,ar:'الْقُدُّوسُ',en:'Al-Quddus',desc:'المنزه عن كل عيب ونقص، الطاهر من كل صفات المخلوقين، الذي تُقدسه الملائكة'},
  {n:5,ar:'السَّلَامُ',en:'As-Salam',desc:'الذي سلِم من كل عيب وآفة، والذي يُسلم عباده في الدنيا والآخرة من العذاب'},
  {n:6,ar:'الْمُؤْمِنُ',en:'Al-Mumin',desc:'الذي صدّق نفسه بكماله، وصدّق أنبياءه بالمعجزات، وأمَّن عباده من الظلم'},
  {n:7,ar:'الْمُهَيْمِنُ',en:'Al-Muhaymin',desc:'الرقيب على كل شيء، الشاهد على خلقه بأعمالهم، الحافظ لأحوالهم'},
  {n:8,ar:'الْعَزِيزُ',en:'Al-Aziz',desc:'القوي الذي لا يُغلب، العزيز الذي لا核酸ل عزته، الذي ينتصر لعباده المؤمنين'},
  {n:9,ar:'الْجَبَّارُ',en:'Al-Jabbar',desc:'الذي قهر كل شيء بعظمته، الذي يجبر كسر عباده، ويُعزز من أطاعه'},
  {n:10,ar:'الْمُتَكَبِّرُ',en:'Al-Mutakabbir',desc:'الذي تكبّر عن صفات المخلوقين، صاحب الكبرياء المطلق في ذاته وصفاته'},
  {n:11,ar:'الْخَالِقُ',en:'Al-Khaliq',desc:'الذي خلق كل شيء من العدم، وأوجد المخلوقات على اختلاف أشكالها وأنواعها'},
  {n:12,ar:'الْبَارِئُ',en:'Al-Bari',desc:'الذي خلق الخلق بريئاً من التفاوت، والذي يبرئ خلقه من العيوب'},
  {n:13,ar:'الْمُصَوِّرُ',en:'Al-Musawwir',desc:'الذي صور المخلوقات على اختلاف صورها وهيئاتها، فلا تشابه في خلقه'},
  {n:14,ar:'الْغَفَّارُ',en:'Al-Ghaffar',desc:'الذي يستر الذنوب في الدنيا، ويتجاوز عنها في الآخرة، كثير المغفرة لمن تاب'},
  {n:15,ar:'الْقَهَّارُ',en:'Al-Qahhar',desc:'الذي قهر كل شيء بقدرته، وأذلّ كل شيء لعظمته، لا يُعصى إلا بإذنه'},
  {n:16,ar:'الْوَهَّابُ',en:'Al-Wahhab',desc:'الذي يهب العطايا بلا مقابل، كثير العطاء لا ينقطع عطاؤه، يُعطي من سأله ومن لم يسأله'},
  {n:17,ar:'الرَّزَّاقُ',en:'Ar-Razzaq',desc:'الذي يرزق جميع خلقه في الدنيا، مؤمنهم وكافرهم، ويُخصص المؤمنين بالرزق الروحاني'},
  {n:18,ar:'الْفَتَّاحُ',en:'Al-Fattah',desc:'الذي يفتح أبواب الرحمة لعباده، ويفتح المغلقات، وينصر المؤمنين على أعدائهم'},
  {n:19,ar:'الْعَلِيمُ',en:'Al-Alim',desc:'الذي أحاط علمه بكل شيء، ما كان وما يكون، وما لم يكن لو كان كيف يكون'},
  {n:20,ar:'الْقَابِضُ',en:'Al-Qabid',desc:'الذي يقبض الأرزاق ويضيّق على من يشاء حكمةً، ويقبض الأرواح عند الموت'},
  {n:21,ar:'الْبَاسِطُ',en:'Al-Basit',desc:'الذي يبسط الرزق ويوسّعه على من يشاء، ويبسط يده بالعطاء للمؤمنين'},
  {n:22,ar:'الْخَافِضُ',en:'Al-Khafid',desc:'الذي يخفض الكفار والطغاة بالذل والصغار، ويضع من يشاء'},
  {n:23,ar:'الرَّافِعُ',en:'Ar-Rafi',desc:'الذي يرفع المؤمنين بالطاعة، ويرفع درجاتهم في الجنة، ويرفع أنبياءه فوق البشر'},
  {n:24,ar:'الْمُعِزُّ',en:'Al-Muizz',desc:'الذي يُعزّ من أطاعه واتبع أمره، فيجعله عزيزاً في الدنيا والآخرة'},
  {n:25,ar:'الْمُذِلُّ',en:'Al-Mudhill',desc:'الذي يُذلّ من عصاه وخالف أمره، فيجعله ذليلاً بين الخلق'},
  {n:26,ar:'السَّمِيعُ',en:'As-Sami',desc:'الذي يسمع كل شيء، ويسمع دعاء عباده، ويعلم ما في القلوب'},
  {n:27,ar:'الْبَصِيرُ',en:'Al-Basir',desc:'الذي يبصر كل شيء وإن دقّ وصغر، ويعلم أعمال العباد الظاهرة والباطنة'},
  {n:28,ar:'الْحَكَمُ',en:'Al-Hakam',desc:'الذي يحكم بين عباده بالحق، ولا يظلم أحداً، وإليه المرجع يوم القيامة'},
  {n:29,ar:'الْعَدْلُ',en:'Al-Adl',desc:'الذي لا يجور ولا يظلم، الذي حكم بالعدل في شرعه وقدره'},
  {n:30,ar:'اللَّطِيفُ',en:'Al-Latif',desc:'الذي يرفق بعباده، ويُوصِل إليهم النعم بأخفى الأسباب، البر بعباده'},
  {n:31,ar:'الْخَبِيرُ',en:'Al-Khabir',desc:'الذي يعلم حقائق الأمور وبواطنها، خبير بما يُعمل ونيّات العاملين'},
  {n:32,ar:'الْحَلِيمُ',en:'Al-Halim',desc:'الذي لا يعاجل بالعقوبة، ويتجاوز عن الذنوب، رفيقاً بعباده في طاعاتهم'},
  {n:33,ar:'الْعَظِيمُ',en:'Al-Azim',desc:'الذي له العظمة المطلقة في ذاته وصفاته وأفعاله، الذي لا أعظم منه'},
  {n:34,ar:'الْغَفُورُ',en:'Al-Ghafur',desc:'الذي يغفر الذنوب مهما كثرت، ولا يبالي بوفرة الذنوب إذا تاب العبد'},
  {n:35,ar:'الشَّكُورُ',en:'Ash-Shakur',desc:'الذي يشكر القليل من العمل، ويُجازي بالكثير، يرضى باليسير ويعطي الجزيل'},
  {n:36,ar:'الْعَلِيُّ',en:'Al-Ali',desc:'الذي له العلو المطلق في ذاته وقدره وقهره، أعلى من كل شيء'},
  {n:37,ar:'الْكَبِيرُ',en:'Al-Kabir',desc:'الذي كبُر كل شيء، وعلا على كل شيء، صاحب الكبرياء المطلقة'},
  {n:38,ar:'الْحَفِيظُ',en:'Al-Hafiz',desc:'الذي يحفظ عباده، ويحفظ أعمالهم، ويحفظ السماوات والأرض من التفاوت'},
  {n:39,ar:'الْمُقِيتُ',en:'Al-Muqit',desc:'الذي يُقيت عباده بالأرزاق، ويُقدّر لكل مخلوق قوته، خالق الأقوات'},
  {n:40,ar:'الْحَسِيبُ',en:'Al-Hasib',desc:'الذي يحاسب عباده على أعمالهم، وكافي عباده المؤمنين، يكفي من توكل عليه'},
  {n:41,ar:'الْجَلِيلُ',en:'Al-Jalil',desc:'الذي له الجلال والعظمة، المتنزه عن النقائص، صاحب الهيبة والوقار'},
  {n:42,ar:'الْكَرِيمُ',en:'Al-Karim',desc:'الذي يُعطي بلا حساب، ويُعطي العطاء الجزيل، كريم في ذاته وأفعاله'},
  {n:43,ar:'الرَّقِيبُ',en:'Ar-Raqib',desc:'الذي يراقب أعمال عباده، الحافظ لكل شيء، الذي لا يغيب عن علمه شيء'},
  {n:44,ar:'الْمُجِيبُ',en:'Al-Mujib',desc:'الذي يجيب دعاء المضطرين، ويستجيب لمن دعاه مخلصاً'},
  {n:45,ar:'الْوَاسِعُ',en:'Al-Wasi',desc:'الذي وسع كل شيء رحمةً وعلماً، والذي وسع خلقه فضله ورزقه'},
  {n:46,ar:'الْحَكِيمُ',en:'Al-Hakim',desc:'الذي أحكم خلق كل شيء، وصنع كل شيء في أحسن صورة، حكيم في شرعه وقدره'},
  {n:47,ar:'الْوَدُودُ',en:'Al-Wadud',desc:'الذي يحب عباده المؤمنين، ويُحبَّ منهم، المحبوب عند أوليائه'},
  {n:48,ar:'الْمَجِيدُ',en:'Al-Majid',desc:'الذي له المجد والعظمة، كريم الأفعال، عظيم الشأن'},
  {n:49,ar:'الْبَاعِثُ',en:'Al-Baith',desc:'الذي يبعث الخلق بعد موتهم، ويبعث رسله إلى عباده، باعث الأعمال يوم القيامة'},
  {n:50,ar:'الشَّهِيدُ',en:'Ash-Shahid',desc:'الذي شهد على كل شيء، لا يغيب عنه شيء، شاهد على أعمال عباده'},
  {n:51,ar:'الْحَقُّ',en:'Al-Haqq',desc:'الذي له الوجود الحق الثابت، الذي لا يزول، وكل ما سواه باطل'},
  {n:52,ar:'الْوَكِيلُ',en:'Al-Wakil',desc:'الذي توكل إليه الأمور، كافي من توكل عليه، القائم بأمور عباده'},
  {n:53,ar:'الْقَوِيُّ',en:'Al-Qawiyy',desc:'الذي له القوة المطلقة، لا يُعجزه شيء، كامل القدرة'},
  {n:54,ar:'الْمَتِينُ',en:'Al-Matin',desc:'الذي له المتانة والقوة الشديدة، الذي لا ينال ولا يُقهر'},
  {n:55,ar:'الْوَلِيُّ',en:'Al-Waliyy',desc:'الذي يتولى المؤمنين بنصره وتوفيقه، مولى المؤمنين وناصرهم'},
  {n:56,ar:'الْحَمِيدُ',en:'Al-Hamid',desc:'الذي يحمد على كل حال، يستحق الحمد كله في ذاته وأفعاله'},
  {n:57,ar:'الْمُحْصِي',en:'Al-Muhsi',desc:'الذي أحصى كل شيء بعلمه، لا يفوته دقيق ولا جليل'},
  {n:58,ar:'الْمُبْدِئُ',en:'Al-Mubdi',desc:'الذي أوجد الخلق من العدم، بدأ خلقهم وأوجدهم'},
  {n:59,ar:'الْمُعِيدُ',en:'Al-Muid',desc:'الذي يعيد الخلق بعد موتهم يوم القيامة، ويعيد الأشياء إلى حالتها الأولى'},
  {n:60,ar:'الْمُحْيِي',en:'Al-Muhyi',desc:'الذي يحيي الموتى، ويحيي الأرض بعد موتها، باعث الحياة'},
  {n:61,ar:'الْمُمِيتُ',en:'Al-Mumit',desc:'الذي يميت الأحياء عند انتهاء آجالهم، وحياة كل حيٍ مؤدية إلى موته'},
  {n:62,ar:'الْحَيُّ',en:'Al-Hayy',desc:'الذي له الحياة الكاملة، حياة لا موت فيها، الباقي الذي لا يفنى'},
  {n:63,ar:'الْقَيُّومُ',en:'Al-Qayyum',desc:'القائم بنفسه، القائم على كل شيء بتدبيره وحفظه، القيّم على أمور خلقه'},
  {n:64,ar:'الْوَاجِدُ',en:'Al-Wajid',desc:'الذي لا يحتاج إلى شيء، الغني الذي يوجد كل ما يُريده'},
  {n:65,ar:'الْمَاجِدُ',en:'Al-Majid',desc:'الذي له المجد والشرف، كثير الإحسان، عظيم الفضل'},
  {n:66,ar:'الْوَاحِدُ',en:'Al-Wahid',desc:'الذي لا ثاني له في ذاته وصفاته وأفعاله، الفرد الصمد'},
  {n:67,ar:'الْأَحَدُ',en:'Al-Ahad',desc:'الذي لا نظير له ولا مثيل، المتفرد بالوحدانية المطلقة'},
  {n:68,ar:'الصَّمَدُ',en:'As-Samad',desc:'السيد الذي يُقصد في الحوائج، الذي لا يحتاج إلى أحد، ويحتاج إليه كل أحد'},
  {n:69,ar:'الْقَادِرُ',en:'Al-Qadir',desc:'الذي له القدرة المطلقة، لا يعجزه شيء في الأرض ولا في السماء'},
  {n:70,ar:'الْمُقْتَدِرُ',en:'Al-Muqtadir',desc:'الذي يُقدّر الأشياء على وجه الإحكام، صاحب القدرة النافذة'},
  {n:71,ar:'الْمُقَدِّمُ',en:'Al-Muqaddim',desc:'الذي يُقدّم من يشاء من خلقه، ويُقدّم الأعمال والآجال بحكمته'},
  {n:72,ar:'الْمُؤَخِّرُ',en:'Al-Muakhkhir',desc:'الذي يُؤخّر من يشاء، ويُؤخّر العقوبة لمن يشاء حكمةً'},
  {n:73,ar:'الْأَوَّلُ',en:'Al-Awwal',desc:'الذي ليس قبله شيء، الذي كانت البداية منه وحدَه، قبل كل شيء'},
  {n:74,ar:'الْآخِرُ',en:'Al-Akhir',desc:'الذي ليس بعده شيء، الباقي بعد فناء خلقه، الذي إليه المنتهى'},
  {n:75,ar:'الظَّاهِرُ',en:'Az-Zahir',desc:'الذي ظهر فوق كل شيء، الظاهر بالأدلة على وجوده ووحدانيته'},
  {n:76,ar:'الْبَاطِنُ',en:'Al-Batin',desc:'الذي احتجب عن أبصار الخلق في الدنيا، المحتجب عن الحواس'},
  {n:77,ar:'الْوَالِي',en:'Al-Wali',desc:'الذي يلي أمر خلقه بالتدبير، المتصرف في شؤون عباده'},
  {n:78,ar:'الْمُتَعَالِي',en:'Al-Mutaali',desc:'الذي تعالى عن صفات المخلوقين، المتنزه عن النقائص والشركاء'},
  {n:79,ar:'الْبَرُّ',en:'Al-Barr',desc:'الذي يُحسن إلى عباده، كثير الخير، الذي يُعطي عباده أكثر مما يستحقون'},
  {n:80,ar:'التَّوَّابُ',en:'At-Tawwab',desc:'الذي يتوب على عباده، ويقبل توبتهم مهما كثُرت، كثير القبول لتوبة التائبين'},
  {n:81,ar:'الْمُنْتَقِمُ',en:'Al-Muntaqim',desc:'الذي ينتقم من العصاة والظلمة، ويُعاقب المجرمين على أفعالهم'},
  {n:82,ar:'الْعَفُوُّ',en:'Al-Afuww',desc:'الذي يعفو عن الذنوب، ويمحوها من الصحف، كثير العفو والصفح'},
  {n:83,ar:'الرَّؤُوفُ',en:'Ar-Rauf',desc:'الذي يرحم عباده برأفته، شديد الرحمة، رحيم بخلقه'},
  {n:84,ar:'مَالِكُ الْمُلْكِ',en:'Malik-ul-Mulk',desc:'الذي يملك الملك كله، يُعزّ من يشاء ويُذل من يشاء، بيده ملكوت كل شيء'},
  {n:85,ar:'ذُو الْجَلَالِ وَالْإِكْرَامِ',en:'Dhul-Jalali wal-Ikram',desc:'الذي يجمع بين الجلال والإكرام، صاحب العظمة والفضل، أهلٌ أن يُجَلَّ ويُكرَم'},
  {n:86,ar:'الْمُقْسِطُ',en:'Al-Muqsit',desc:'الذي يعدل بين عباده، العادل في حكمه، الذي لا يجور'},
  {n:87,ar:'الْجَامِعُ',en:'Al-Jami',desc:'الذي يجمع الخلائق يوم القيامة، ويجمع بين الأشياء المتفرقة'},
  {n:88,ar:'الْغَنِيُّ',en:'Al-Ghani',desc:'الذي لا يحتاج إلى أحد، الغني المطلق الذي لا تنفد خزائنه'},
  {n:89,ar:'الْمُغْنِي',en:'Al-Mughni',desc:'الذي يُغني عباده، ويُغني من يشاء من فضله، معطي الاستغناء'},
  {n:90,ar:'الْمَانِعُ',en:'Al-Mani',desc:'الذي يمنع من يشاء، ويمنع العذاب عمَّن يشاء، حامي عباده'},
  {n:91,ar:'الضَّارُّ',en:'Ad-Darr',desc:'الذي يُضرّ من يشاء بحكمته، والذي يُقدّر الضر لمن يستحقه'},
  {n:92,ar:'النَّافِعُ',en:'An-Nafi',desc:'الذي ينفع من يشاء، والذي بيده النفع والضر، دافع النفع لمن أطاعه'},
  {n:93,ar:'النُّورُ',en:'An-Nur',desc:'الذي نوّر السماوات والأرض، ونوّر قلوب المؤمنين بالإيمان، نورٌ في ذاته ومنوّرٌ لغيره'},
  {n:94,ar:'الْهَادِي',en:'Al-Hadi',desc:'الذي يهدي عباده إلى الحق، ويهديهم إلى مصالحهم في الدنيا والآخرة'},
  {n:95,ar:'الْبَدِيعُ',en:'Al-Badi',desc:'الذي أبدع الخلق على غير مثال سبق، مُنشئ الأشياء بديعاً في صورها'},
  {n:96,ar:'الْبَاقِي',en:'Al-Baqi',desc:'الذي يبقى بعد فناء خلقه، الدائم الوجود الذي لا يفنى ولا يزول'},
  {n:97,ar:'الْوَارِثُ',en:'Al-Warith',desc:'الذي يرث الأرض ومن عليها، الباقي بعد فناء الكل'},
  {n:98,ar:'الرَّشِيدُ',en:'Ar-Rashid',desc:'الذي يُرشد عباده إلى الخير، الحكيـم الذي يضع الأشياء مواضعها'},
  {n:99,ar:'الصَّبُورُ',en:'As-Sabur',desc:'الذي لا يعاجل بالعقوبة، ويتأنّى مع القدرة على الانتقام، كثير الصفح'}
];

/* ════════════════════════════════════════════════════════════
   VERSE POOL — each entry: { ref, surah, ayah, t, ta, ben }
   t = text, ta = tafsir, ben = benefit
   Used by "آية اليوم" — random pick per click
   ════════════════════════════════════════════════════════════ */
const VERSE_POOL = [
  {ref:'الفاتحة: ١-٧',surah:1,ayah:1,t:'بِسْمِ اللَّهِ الرَّحْمَٰنِ الرَّحِيمِ ﴿١﴾ الْحَمْدُ لِلَّهِ رَبِّ الْعَالَمِينَ ﴿٢﴾ الرَّحْمَٰنِ الرَّحِيمِ ﴿٣﴾ مَالِكِ يَوْمِ الدِّينِ ﴿٤﴾ إِيَّاكَ نَعْبُدُ وَإِيَّاكَ نَسْتَعِينُ ﴿٥﴾ اهْدِنَا الصِّرَاطَ الْمُسْتَقِيمَ ﴿٦﴾ صِرَاطَ الَّذِينَ أَنْعَمْتَ عَلَيْهِمْ غَيْرِ الْمَغْضُوبِ عَلَيْهِمْ وَلَا الضَّالِّينَ ﴿٧﴾',ta:'أمّ القرآن وأساسه، جمعت أصول العقيدة ومراتب العبادة. بدأت باسم الله طلباً للبركة، ثم أثبتت الحمد لله رباً للعالمين، ثم خصصت الرحمة، ثم أثبتت الملك يوم القيامة، ثم أفراد الله بالعبادة والاستعانة، ثم طلبت الهداية للصراط المستقيم، وهو طريق النبيين والصالحين، وتميّز عن طريق المغضوب عليهم (اليهود) والضالين (النصارى).',ben:'تكرارها في كل ركعة يعيد ترتيب الأولويات: الله وحده المعبود، وإياه المستعان، وإليه المنتهى.'},
  {ref:'البقرة: ١٥٣',surah:2,ayah:153,t:'يَا أَيُّهَا الَّذِينَ آمَنُوا اسْتَعِينُوا بِالصَّبْرِ وَالصَّلَاةِ ۚ إِنَّ اللَّهَ مَعَ الصَّابِرِينَ',ta:'خطاب للمؤمنين بطلب العون على أمور الدين والدنيا، بالصبر على الطاعات وعن المعاصي وعلى أقدار الله، وبالصلاة التي تنهى عن الفحشاء وتقرّب إلى الله. ومعية الله للصابرين معية خاصة تحفظهم وتؤيدهم.',ben:'عند الضيق، صلِّ ركعتين — فالصلاة قُربٌ ومعية، والصبر سكينة.'},
  {ref:'البقرة: ١٨٦',surah:2,ayah:186,t:'وَإِذَا سَأَلَكَ عِبَادِي عَنِّي فَإِنِّي قَرِيبٌ ۖ أُجِيبُ دَعْوَةَ الدَّاعِ إِذَا دَعَانِ ۖ فَلْيَسْتَجِيبُوا لِي وَلْيُؤْمِنُوا بِي لَعَلَّهُمْ يَرْشُدُونَ',ta:'جواب الله عن سؤال العباد عن قربه، فبيّن أنه قريب من عباده بعلمه وإجابته، يجيب دعوة الداعي إذا دعاه بشرط الإخلاص. ثم طلب منهم الاستجابة له بالإيمان والطاعة، لعلهم يرشدون.',ben:'لا حجاب بينك وبين الله، فقط ارفع يديك وقل: يا رب.'},
  {ref:'البقرة: ٢٨٦',surah:2,ayah:286,t:'لَا يُكَلِّفُ اللَّهُ نَفْسًا إِلَّا وُسْعَهَا ۚ لَهَا مَا كَسَبَتْ وَعَلَيْهَا مَا اكْتَسَبَتْ ۗ رَبَّنَا لَا تُؤَاخِذْنَا إِن نَّسِينَا أَوْ أَخْطَأْنَا',ta:'بيان لعدل الله في تكليف العباد، فلا يُكلّف نفساً فوق طاقتها، وللنفس ما فعلته من خير، وعليها ما اقترفته من شر. ثم دعاء برفع المؤاخذة عن النسيان والخطأ، وقد استجاب الله ذلك للأمة.',ben:'رحمتك تسع تقصيرك، فلا تيأس، وعُد إليه في كل لحظة.'},
  {ref:'آل عمران: ١٣٩',surah:3,ayah:139,t:'وَلَا تَهِنُوا وَلَا تَحْزَنُوا وَأَنتُمُ الْأَعْلَوْنَ إِن كُنتُم مُّؤْمِنِينَ',ta:'نهي عن الضعف والحزن، وبشارة بأن المؤمنين الأعلون، أي الغالبون، بسبب إيمانهم. فالإيمان قوة لا تُقهر ما دام صاحبه متمسكاً به.',ben:'مهما طال ليل المحن، فالفجر للمؤمنين، أنت الأعلى بإيمانك.'},
  {ref:'النساء: ٣٦',surah:4,ayah:36,t:'وَاعْبُدُوا اللَّهَ وَلَا تُشْرِكُوا بِهِ شَيْئًا وَبِالْوَالِدَيْنِ إِحْسَانًا',ta:'أمر بعبادة الله وحده وترك الشرك، ثم بالإحسان للوالدين، فجمع بين حق الله وحق الوالدين، إذ هما أعظم الخلق حقاً بعد الله.',ben:'رضا الله في رضا الوالدين، وسخطه في سخطهما.'},
  {ref:'الأنعام: ١٦٢',surah:6,ayah:162,t:'قُلْ إِنَّ صَلَاتِي وَنُسُكِي وَمَحْيَايَ وَمَمَاتِي لِلَّهِ رَبِّ الْعَالَمِينَ',ta:'توجيه للنبي ﷺ أن يُعلن إخلاصه لله في صلاته ونسكه، بل في حياته كلها ومماته. فالمؤمن حياته كلها لله، في مشيه وكلامه وعمله وموته.',ben:'اجعل كل يومك عبادة: نومك، طعامك، عملك، كلك لله.'},
  {ref:'الأعراف: ٥٦',surah:7,ayah:56,t:'وَلَا تُفْسِدُوا فِي الْأَرْضِ بَعْدَ إِصْلَاحِهَا وَادْعُوهُ خَوْفًا وَطَمَعًا ۚ إِنَّ رَحْمَتَ اللَّهِ قَرِيبٌ مِّنَ الْمُحْسِنِينَ',ta:'نهي عن الإفساد في الأرض بعد إصلاح الله لها بالرسل والكتب، وأمر بدعاء الله بين الخوف والطمع، فلا يأمن عذاب الله ولا يقنط من رحمته، ووعد بأن رحمته قريبٌ من المحسنين.',ben:'الإحسان مفتاح الرحمات، ابدأ بإحسانٍ في عملٍ صغير.'},
  {ref:'الرعد: ٢٨',surah:13,ayah:28,t:'الَّذِينَ آمَنُوا وَتَطْمَئِنُّ قُلُوبُهُم بِذِكْرِ اللَّهِ ۗ أَلَا بِذِكْرِ اللَّهِ تَطْمَئِنُّ الْقُلُوبُ',ta:'وصف المؤمنين بأن قلوبهم تطمئن بذكر الله، فالقلوب لا تسكن ولا تطمئن إلا بذكر خالقها، فإذا ذكرت الله سكنت وإذا غفلت عنه اضطربت.',ben:'الذِّكرُ سكينةٌ فورية، اجعله زادك في كل حال.'},
  {ref:'إبراهيم: ٧',surah:14,ayah:7,t:'وَإِذْ تَأَذَّنَ رَبُّكُمْ لَئِن شَكَرْتُمْ لَأَزِيدَنَّكُمْ ۖ وَلَئِن كَفَرْتُمْ إِنَّ عَذَابِي لَشَدِيدٌ',ta:'إعلان رباني مباشر: الشكر سبب لزيادة النعمة، وكفر النعمة سبب للعذاب. والشكر بالقلب اعتراف، وباللسان ثناء، وبالجوارح طاعة.',ben:'اشكر على القليل، يُمد لك الكثير، فالشكر مطيّة النعم.'},
  {ref:'النحل: ٩٧',surah:16,ayah:97,t:'مَنْ عَمِلَ صَالِحًا مِّن ذَكَرٍ أَوْ أُنثَىٰ وَهُوَ مُؤْمِنٌ فَلَنُحْيِيَنَّهُ حَيَاةً طَيِّبَةً ۖ وَلَنَجْزِيَنَّهُمْ أَجْرَهُم بِأَحْسَنِ مَا كَانُوا يَعْمَلُونَ',ta:'وعد من الله لمن عمل صالحاً من ذكر أو أنثى بشرط الإيمان، أن يحييه حياة طيبة في الدنيا (بالقناعة والرضا) ويجازيه في الآخرة بأحسن أعماله.',ben:'السعادة الحقيقية ليست في المال، بل في عملٍ صالحٍ مع إيمان.'},
  {ref:'الإسراء: ٨٠',surah:17,ayah:80,t:'وَقُل رَّبِّ أَدْخِلْنِي مُدْخَلَ صِدْقٍ وَأَخْرِجْنِي مُخْرَجَ صِدْقٍ وَاجْعَل لِّي مِن لَّدُنكَ سُلْطَانًا نَّصِيرًا',ta:'دعاء النبي ﷺ بأن يُدخله الله مدخل صدق (الهجرة المباركة) ويُخرجه مخرج صدق، وأن يجعل له من عنده سلطاناً نصيراً (حجة ظاهرة وعزاً).',ben:'قبل أي خطوة كبيرة، قل هذا الدعاء: ادخلني وأخرجني بالصدق.'},
  {ref:'الكهف: ١٠',surah:18,ayah:10,t:'إِذْ أَوَى الْفِتْيَةُ إِلَى الْكَهْفِ فَقَالُوا رَبَّنَا آتِنَا مِن لَّدُنكَ رَحْمَةً وَهَيِّئْ لَنَا مِنْ أَمْرِنَا رَشَدًا',ta:'دعاء أصحاب الكهف عند اعتزالهم قومهم، طلبوا من الله رحمةً تُنزلها عليهم، وتيسيراً لأمرهم إلى الرشد والصلاح، فجمعوا بين طلب الرحمة والتوفيق.',ben:'عند الاضطرار: اللهم ارحمني ويسّر لي رشداً.'},
  {ref:'مريم: ٤',surah:19,ayah:4,t:'قَالَ رَبِّ إِنِّي وَهَنَ الْعَظْمُ مِنِّي وَاشْتَعَلَ الرَّأْسُ شَيْبًا وَلَمْ أَكُن بِدُعَائِكَ رَبِّ شَقِيًّا',ta:'دعاء زكريا عليه السلام، بيّن ضعفه وكبر سنه، ثم ذكر أنه لم يكن بدعائه شقياً، أي ما دعا ربه قط إلا استجاب له، تواضعاً وثناء على الله.',ben:'ابدأ دعاءك بالاعتراف بضعفك، واختمه بالثناء على إجابة الله لك.'},
  {ref:'طه: ١١٤',surah:20,ayah:114,t:'فَتَعَالَى اللَّهُ الْمَلِكُ الْحَقُّ ۗ وَلَا تَعْجَلْ بِالْقُرْآنِ مِن قَبْلِ أَن يُقْضَىٰ إِلَيْكَ وَحْيُهُ ۖ وَقُل رَّبِّ زِدْنِي عِلْمًا',ta:'تنزيه لله عن كل نقص، وأمر للنبي ﷺ بعدم العجلة في قراءة القرآن قبل إكمال الوحي، ثم دعاء بطلب العلم، فالعلم من أشرف ما يُطلب.',ben:'قل كل صباح: ربِّ زدني علماً، فالعلم نور يهديك.'},
  {ref:'النور: ٣٥',surah:24,ayah:35,t:'اللَّهُ نُورُ السَّمَاوَاتِ وَالْأَرْضِ ۚ مَثَلُ نُورِهِ كَمِشْكَاةٍ فِيهَا مِصْبَاحٌ ۖ الْمِصْبَاحُ فِي زُجَاجَةٍ ۖ الزُّجَاجَةُ كَأَنَّهَا كَوْكَبٌ دُرِّيٌّ',ta:'مثال ل نور الله في السماوات والأرض، بنور الكون كله منه، وضربه مثلاً بمشكاة فيها مصباح في زجاجة شديدة الضياء، فكذلك نور الله في قلوب المؤمنين، يزداد بسماعه القرآن.',ben:'اسأل الله أن يجعل في قلبك نوراً، فالنور يهديك في كل ظلام.'},
  {ref:'الفرقان: ٧٤',surah:25,ayah:74,t:'وَالَّذِينَ يَقُولُونَ رَبَّنَا هَبْ لَنَا مِنْ أَزْوَاجِنَا وَذُرِّيَّاتِنَا قُرَّةَ أَعْيُنٍ وَاجْعَلْنَا لِلْمُتَّقِينَ إِمَامًا',ta:'دعاء عباد الرحمن أن يهب الله لهم من أزواجهم وذرياتهم قرة عين (سعادةً وصلاحاً)، وأن يجعلهم للمتقين إماماً في الخير، يقتدى بهم.',ben:'استثمر دعاءك لزوجك وأولادك، فهم قرة عينك في الدنيا والآخرة.'},
  {ref:'لقمان: ١٣',surah:31,ayah:13,t:'وَإِذْ قَالَ لُقْمَانُ لِابْنِهِ وَهُوَ يَعِظُهُ يَا بُنَيَّ لَا تُشْرِكْ بِاللَّهِ ۖ إِنَّ الشِّرْكَ لَظُلْمٌ عَظِيمٌ',ta:'موعظة لقمان لابنه بتجنب الشرك، فالشرك ظلم للنفس بتعجيلها العذاب، وظلم لله بوضع غيره في مقامه.',ben:'علّم أولادك التوحيد قبل أي شيء، فهو أصل السعادة.'},
  {ref:'الزمر: ٥٣',surah:39,ayah:53,t:'قُلْ يَا عِبَادِيَ الَّذِينَ أَسْرَفُوا عَلَىٰ أَنفُسِهِمْ لَا تَقْنَطُوا مِن رَّحْمَةِ اللَّهِ ۚ إِنَّ اللَّهَ يَغْفِرُ الذُّنُوبَ جَمِيعًا',ta:'نداء رباني للعصاة والمذنبين بعدم القنوط من رحمة الله، فإن الله يغفر الذنوب جميعاً لمن تاب، مهما عظمت، فباب التوبة مفتوح.',ben:'لا تيأس أبداً، باب التوبة مفتوح حتى طلوع الشمس من مغربها.'},
  {ref:'غافر: ٦٠',surah:40,ayah:60,t:'وَقَالَ رَبُّكُمُ ادْعُونِي أَسْتَجِبْ لَكُمْ ۚ إِنَّ الَّذِينَ يَسْتَكْبِرُونَ عَنْ عِبَادَتِي سَيَدْخُلُونَ جَهَنَّمَ دَاخِرِينَ',ta:'أمر رباني بدعائه ووعده بالإجابة، وتوعّد المستكبرين عن عبادته بدخول جهنم صاغرين. والدعاء رأس العبادة.',ben:'الدعاء مفتاح الحاجات، فلا تتركه مهما طال الانتظار.'},
  {ref:'الشورى: ١٣',surah:42,ayah:13,t:'شَرَعَ لَكُم مِّنَ الدِّينِ مَا وَصَّىٰ بِهِ نُوحًا وَالَّذِي أَوْحَيْنَا إِلَيْكَ وَمَا وَصَّيْنَا بِهِ إِبْرَاهِيمَ وَمُوسَىٰ وَعِيسَىٰ',ta:'بيان أن دين الإسلام واحد في أصله، شُرع لكل الأنبياء: توحيد الله وإفراده بالعبادة، وإن اختلفت الشرائع في الفروع.',ben:'الإسلام دين الأنبياء جميعاً، فالزمه تكن متبعاً للحق.'},
  {ref:'الرعد: ١١',surah:13,ayah:11,t:'لَهُ مُعَقِّبَاتٌ مِّن بَيْنِ يَدَيْهِ وَمِنْ خَلْفِهِ يَحْفَظُونَهُ مِنْ أَمْرِ اللَّهِ ۗ إِنَّ اللَّهَ لَا يُغَيِّرُ مَا بِقَوْمٍ حَتَّىٰ يُغَيِّرُوا مَا بِأَنفُسِهِمْ',ta:'للإنسان ملائكة يحفظونه بأمر الله، ولا يتغيّر حال قومٍ من رخاء إلى شدة إلا إذا غيّروا ما بأنفسهم من الطاعة إلى المعصية.',ben:'تغيير الأحوال يبدأ من تغيير النفس، فغيّر سرك يغيّر الله علانيتك.'},
  {ref:'الحجرات: ١٣',surah:49,ayah:13,t:'يَا أَيُّهَا النَّاسُ إِنَّا خَلَقْنَاكُم مِّن ذَكَرٍ وَأُنثَىٰ وَجَعَلْنَاكُمْ شُعُوبًا وَقَبَائِلَ لِتَعَارَفُوا ۚ إِنَّ أَكْرَمَكُمْ عِندَ اللَّهِ أَتْقَاكُمْ',ta:'خطاب للبشر جميعاً بأنهم من أصل واحد، واختلافهم إلى شعوب وقبائل لحصول التعارف لا للتفاخر، وأن معيار التفاضل عند الله هو التقوى لا النسب.',ben:'قيمتك عند الله بتقواك لا بنسبك، فاجتهد في التقوى.'},
  {ref:'الذاريات: ٥٦',surah:51,ayah:56,t:'وَمَا خَلَقْتُ الْجِنَّ وَالْإِنسَ إِلَّا لِيَعْبُدُونِ',ta:'بيان للحكمة من خلق الجن والإنس، وهي عبادة الله وحده، فمن أطاعه فقد أدى ما خُلق له، ومن عصاه فقد خالف الغاية من وجوده.',ben:'لكل مخلوق غاية، غايتك العبادة، فلا تشغل نفسك عنها.'},
  {ref:'القمر: ١٧',surah:54,ayah:17,t:'وَلَقَدْ يَسَّرْنَا الْقُرْآنَ لِلذِّكْرِ فَهَلْ مِن مُّدَّكِرٍ',ta:'بيان أن الله يسّر القرآن للحفظ والفهم والتدبر، فهو سهل على اللسان، واضح المعاني، فهل من متعظٍ يتأمله ويعمل به.',ben:'القرآن ميسّر، فلا تقل: لا أستطيع حفظه، ابدأ وستجد العون.'},
  {ref:'الرحمن: ١٣',surah:55,ayah:13,t:'فَبِأَيِّ آلَاءِ رَبِّكُمَا تُكَذِّبَانِ',ta:'تكرار في السينة إثباتاً لنعم الله على الإنس والجن، فبأي نعمة تكذبان بعد هذا البيان؟ وكل آية فيها نعمة تستوجب الشكر.',ben:'احصر نعم الله عليك، ستجدها لا تُحصى، فاشكر.'},
  {ref:'الحديد: ٣',surah:57,ayah:3,t:'هُوَ الْأَوَّلُ وَالْآخِرُ وَالظَّاهِرُ وَالْبَاطِنُ ۖ وَهُوَ بِكُلِّ شَيْءٍ عَلِيمٌ',ta:'أربع صفات لله تجمع كماله: الأول فلا شيء قبله، والآخر فلا شيء بعده، والظاهر فلا شيء فوقه، والباطن فلا شيء دونه، عليم بكل شيء.',ben:'كن مع الأول تكون آخراً، وكن مع الظاهر تكون ظاهراً، والزم الباطن يُحفظ سرك.'},
  {ref:'الملك: ٢',surah:67,ayah:2,t:'الَّذِي خَلَقَ الْمَوْتَ وَالْحَيَاةَ لِيَبْلُوَكُمْ أَيُّكُمْ أَحْسَنُ عَمَلًا ۚ وَهُوَ الْعَزِيزُ الْغَفُورُ',ta:'بيان أن الله خلق الموت والحياة اختباراً للعباد أيهم أحسن عملاً، لا أكثر عملاً، فالعبرة بالإخلاص والإتقان.',ben:'اجعل كل عملك طيباً: خالصاً لوجه الله، ومتقناً للناس.'},
  {ref:'الانفطار: ٦-٨',surah:82,ayah:6,t:'يَا أَيُّهَا الْإِنسَانُ مَا غَرَّكَ بِرَبِّكَ الْكَرِيمِ ﴿٦﴾ الَّذِي خَلَقَكَ فَسَوَّاكَ فَعَدَلَكَ ﴿٧﴾ فِي أَيِّ صُورَةٍ مَّا شَاءَ رَكَّبَكَ ﴿٨﴾',ta:'سؤال توبيخي للإنسان: ما الذي خدعه حتى عصى ربه الكريم؟ ثم ذكر نعمه عليه بخلقه وتسويته وتعدیل صورته، فاستحق الشكر لا الكفر.',ben:'تأمل في خلقك، ستجد إحساناً يلزمك الشكر لا التمرد.'},
  {ref:'الضحى: ٥',surah:93,ayah:5,t:'وَلَسَوْفَ يُعْطِيكَ رَبُّكَ فَتَرْضَىٰ',ta:'وعد للنبي ﷺ من ربه بعطاء يرضيه في الدنيا (النصر والفتح) وفي الآخرة (الشفاعة)، فالرضا غاية المؤمن.',ben:'اجعل همّك رضا الله، يرضيك الله بما يعطيك.'},
  {ref:'الشرح: ٥-٦',surah:94,ayah:5,t:'فَإِنَّ مَعَ الْعُسْرِ يُسْرًا ﴿٥﴾ إِنَّ مَعَ الْعُسْرِ يُسْرًا ﴿٦﴾',ta:'تكرار اليُسر مع العسر مرتين للتأكيد، فإذا اشتد العسر، فاليسر قادم لا محالة. وفي الحديث: «واحدة لا تُغلب اثنتين».',ben:'مهما اشتد الكرب، الفرج قريب، فلا تيأس.'},
  {ref:'العصر: ١-٣',surah:103,ayah:1,t:'وَالْعَصْرِ ﴿١﴾ إِنَّ الْإِنسَانَ لَفِي خُسْرٍ ﴿٢﴾ إِلَّا الَّذِينَ آمَنُوا وَعَمِلُوا الصَّالِحَاتِ وَتَوَاصَوْا بِالْحَقِّ وَتَوَاصَوْا بِالصَّبْرِ ﴿٣﴾',ta:'قسم بالعصر (الزمن) أن الإنسان في خسارة إلا من اجتمعت فيه أربع: الإيمان، والعمل الصالح، والتواصي بالحق، والتواصي بالصبر. وهي أركان النجاة.',ben:'اسأل نفسك كل ليلة: هل حققت أركان النجاة الأربعة اليوم؟'},
  {ref:'الإخلاص: ١-٤',surah:112,ayah:1,t:'قُلْ هُوَ اللَّهُ أَحَدٌ ﴿١﴾ اللَّهُ الصَّمَدُ ﴿٢﴾ لَمْ يَلِدْ وَلَمْ يُولَدْ ﴿٣﴾ وَلَمْ يَكُن لَّهُ كُفُوًا أَحَدٌ ﴿٤﴾',ta:'سورة تعدل ثلث القرآن، لأنها أخلصت التوحيد. تنفي عن الله الشريك والوالد والولد والمماثل، وتثبت الأحدية والصمدية.',ben:'اقرأها ثلاث مرات صباحاً ومساءً، تكفيك من كل شيء.'},
  {ref:'الزلزلة: ٧-٨',surah:99,ayah:7,t:'فَمَن يَعْمَلْ مِثْقَالَ ذَرَّةٍ خَيْرًا يَرَهُ ﴿٧﴾ وَمَن يَعْمَلْ مِثْقَالَ ذَرَّةٍ شَرًّا يَرَهُ ﴿٨﴾',ta:'إثبات دقيق للجزاء، فأقل خيرٍ يُرى ثوابه، وأقل شرٍ يُرى عقابه، فلا صغيرة مع الإصرار ولا كبيرة مع الاستغفار.',ben:'لا تحتقر أي خير أو شر، فالذرة تُوزن عند ربك.'},
  {ref:'الأنبياء: ١٠٧',surah:21,ayah:107,t:'وَمَا أَرْسَلْنَاكَ إِلَّا رَحْمَةً لِّلْعَالَمِينَ',ta:'بيان أن بعثة النبي ﷺ رحمة للعالمين كلهم، مؤمنهم وكافرهم، إنسهم وجنهم، حتى الحيوانات انتفعت بدعوته بترك التعذيب.',ben:'كن رحمة لمن حولك، تكن متبعاً لسنّة نبيك.'},
  {ref:'الإسراء: ٢٣',surah:17,ayah:23,t:'وَقَضَىٰ رَبُّكَ أَلَّا تَعْبُدُوا إِلَّا إِيَّاهُ وَبِالْوَالِدَيْنِ إِحْسَانًا ۚ إِمَّا يَبْلُغَنَّ عِندَكَ الْكِبَرَ أَحَدُهُمَا أَوْ كِلَاهُمَا فَلَا تَقُل لَّهُمَا أُفٍّ',ta:'أمر جازم بتوحيد الله والإحسان للوالدين، خصوصاً عند الكبر، حتى لا يُقال لهما "أفٍّ" التي هي أدنى مراتب التضجر، فكيف بما فوقها.',ben:'كلم أمك وأباك اليوم بكل احترام، ولا تنطق بـ"أف" ولو كنت متعباً.'},
  {ref:'النحل: ٩٠',surah:16,ayah:90,t:'إِنَّ اللَّهَ يَأْمُرُ بِالْعَدْلِ وَالْإِحْسَانِ وَإِيتَاءِ ذِي الْقُرْبَىٰ وَيَنْهَىٰ عَنِ الْفَحْشَاءِ وَالْمُنكَرِ وَالْبَغْيِ',ta:'جمعت الآية مكارم الأخلاق: العدل (إعطاء كل ذي حق حقه)، والإحسان (الزيادة على الواجب)، وإيتاء ذي القربى، ونهت عن ضدها من الفحشاء والمنكر والبغي.',ben:'اجعل هذه الآية دستورك في تعاملاتك اليومية.'},
  {ref:'البقرة: ١٥٥',surah:2,ayah:155,t:'وَلَنَبْلُوَنَّكُم بِشَيْءٍ مِّنْ خَوْفٍ وَجُوعٍ وَنَقْصٍ مِّنَ الْأَمْوَالِ وَالْأَنفُسِ وَالثَّمَرَاتِ ۗ وَبَشِّرِ الصَّابِرِينَ',ta:'بيان أن الابتلاء سُنّة الله في عباده، بالخوف والجوع ونقص الأموال والأنفس والثمرات، وبشارة للصابرين بثوابهم العظيم.',ben:'الابتلاء تنقية، فإذا ابتُليت فاحمد الله أن الابتلاء في الدنيا لا في الآخرة.'},
  {ref:'آل عمران: ١٥٩',surah:3,ayah:159,t:'فَبِمَا رَحْمَةٍ مِّنَ اللَّهِ لِنتَ لَهُمْ ۖ وَلَوْ كُنتَ فَظًّا غَلِيظَ الْقَلْبِ لَانفَضُّوا مِنْ حَوْلِكَ',ta:'بيان أن رحمة الله جعلت النبي ﷺ ليّناً لأصحابه، ولو كان فظاً غليظ القلب لانفضّوا عنه. وفيه الحث على اللين في الدعوة والتعامل.',ben:'اللين يجمع القلوب، والغلظة تفرّقها، فالزم الرفق.'},
  {ref:'النساء: ٥٩',surah:4,ayah:59,t:'يَا أَيُّهَا الَّذِينَ آمَنُوا أَطِيعُوا اللَّهَ وَأَطِيعُوا الرَّسُولَ وَأُولِي الْأَمْرِ مِنكُمْ',ta:'أمر بطاعة الله ورسوله، ثم بطاعة أولي الأمر (الولاة والعلماء) ما لم يأمروا بمعصية، فطاعة المخلوق مقيدة بطاعة الخالق.',ben:'السمع والطاعة في المعروف أساس الاستقرار، فلا تخرج على جماعة المسلمين.'},
  {ref:'الأنفال: ٢٨',surah:8,ayah:28,t:'وَاعْلَمُوا أَنَّمَا أَمْوَالُكُمْ وَأَوْلَادُكُمْ فِتْنَةٌ ۚ وَأَنَّ اللَّهَ عِندَهُ أَجْرٌ عَظِيمٌ',ta:'تحذير من الافتتان بالمال والأولاد، فإنهما قد يُشغلان عن الطاعة، والله عنده أجرٌ عظيم لمن آثر طاعته.',ben:'استخدم مالك وأولادك في طاعة الله، تكن فتنتهم نعمة لا نقمة.'},
  {ref:'التوبة: ٤٠',surah:9,ayah:40,t:'إِلَّا تَنصُرُوهُ فَقَدْ نَصَرَهُ اللَّهُ ۖ إِذْ أَخْرَجَهُ الَّذِينَ كَفَرُوا ثَانِيَ اثْنَيْنِ',ta:'بيان أن نصر الله لنبيه قديم، فقد نصره في الغار عندما هاجر، وهو ثاني اثنين مع أبي بكر، فالنصر من الله لا من الناس.',ben:'إذا تخلى عنك الناس، فالله معك، فلا تضعف.'},
  {ref:'الأنعام: ٥٩',surah:6,ayah:59,t:'وَعِندَهُ مَفَاتِحُ الْغَيْبِ لَا يَعْلَمُهَا إِلَّا هُوَ ۚ وَيَعْلَمُ مَا فِي الْبَرِّ وَالْبَحْرِ',ta:'إثبات أن مفاتيح الغيب بيد الله وحده، وأن علمه محيط بكل شيء في البر والبحر، فلا يخفى عليه شيء.',ben:'إذا ضاقت بك السبل، فمفاتيح الفرج بيد الله، اسأله.'},
  {ref:'هود: ٨٨',surah:11,ayah:88,t:'قَالَ يَا قَوْمِ أَرَأَيْتُمْ إِن كُنتُّ عَلَىٰ بَيِّنَةٍ مِّن رَّبِّي وَرَزَقَنِي مِنْهُ رِزْقًا حَسَنًا',ta:'دعوة شعيب عليه السلام قومه بالحكمة، بيّن أنه على بينة من ربه، ويسألهم: كيف أعصي من هداني ورزقني؟ وهو منهج الدعاة.',ben:'إذا دعوت أحداً، فابدأ ببيان ما أنت عليه من حق، ولا تُعنّف.'},
  {ref:'يوسف: ٤',surah:12,ayah:4,t:'إِذْ قَالَ يُوسُفُ لِأَبِيهِ يَا أَبَتِ إِنِّي رَأَيْتُ أَحَدَ عَشَرَ كَوْكَبًا وَالشَّمْسَ وَالْقَمَرَ رَأَيْتُهُمْ لِي سَاجِدِينَ',ta:'بداية قصة يوسف، رؤيا رآها، فعبّرها أبوه يعقوب بأنها ستجعله سيداً على إخوته ووالديه، فحذّره من قصدهم بالسوء.',ben:'الرؤيا الصالحة يُؤيّد الله بها المؤمن، فاحفظ ما ترى من خير.'},
  {ref:'يوسف: ٨٧',surah:12,ayah:87,t:'يَا بَنِيَّ اذْهَبُوا فَتَحَسَّسُوا مِن يُوسُفَ وَأَخِيهِ وَلَا تَيْأَسُوا مِن رَّوْحِ اللَّهِ',ta:'وصية يعقوب عليه السلام لبنيه بعدم اليأس من رحمة الله، حتى في أشد الظروف. فالرجاء في الله بابٌ مفتوح.',ben:'لا تيأس من روح الله، حتى ولو طال البلاء، فالفرج آتٍ.'},
  {ref:'الحجر: ٩',surah:15,ayah:9,t:'إِنَّا نَحْنُ نَزَّلْنَا الذِّكْرَ وَإِنَّا لَهُ لَحَافِظُونَ',ta:'وعد رباني بحفظ القرآن من التحريف والضياع، فالقرآن محفوظ بحفظ الله إلى يوم القيامة، وقد تكفّل الله به.',ben:'القرآن محفوظ، فاحفظ أنت منه ما تستطيع، يكن لك نوراً.'},
  {ref:'الإسراء: ٣٢',surah:17,ayah:32,t:'وَلَا تَقْرَبُوا الزِّنَىٰ ۖ إِنَّهُ كَانَ فَاحِشَةً وَسَاءَ سَبِيلًا',ta:'نهي عن قربان الزنا، لا فقط فعله، لأن المقدمات تؤدي إليه. ووصف بأنه فاحشة (شديدة القبح) وساء سبيلاً.',ben:'اغلق باب الذنوب من باب المقدمات، فاحذر ما يوصل إليها.'},
  {ref:'مريم: ٩٦',surah:19,ayah:96,t:'إِنَّ الَّذِينَ آمَنُوا وَعَمِلُوا الصَّالِحَاتِ سَيَجْعَلُ لَهُمُ الرَّحْمَٰنُ وُدًّا',ta:'وعد بأن المؤمنين العاملين الصالحات يجعل لهم الرحمن وُدّاً في قلوب الناس، فيحبهم الخلق بلا سبب ظاهر، لمحبة الله لهم.',ben:'اطلب ودّ الناس بأن تعمل ما يُحببه الله فيك.'},
  {ref:'طه: ١٢٤',surah:20,ayah:124,t:'وَمَنْ أَعْرَضَ عَن ذِكْرِي فَإِنَّ لَهُ مَعِيشَةً ضَنكًا وَنَحْشُرُهُ يَوْمَ الْقِيَامَةِ أَعْمَىٰ',ta:'تحذير من الإعراض عن ذكر الله (القرآن)، فجزاؤه ضنك في الدنيا (ضيق الصدر) وعذاب في الآخرة، فالذكر حياة القلوب.',ben:'إذا ضاق صدرك، فعلك الإعراض عن ذكر الله، فالزم الذكر.'},
  {ref:'المؤمنون: ١',surah:23,ayah:1,t:'قَدْ أَفْلَحَ الْمُؤْمِنُونَ',ta:'بشارة بالفلاح للمؤمنين، ثم بيّن صفاتهم في عشر آيات: خشوع في الصلاة، إعراض عن اللغو، إيتاء الزكاة، حفظ الفروج، حفظ الأمانة، وفاء بالعهد، حفظ الصلوات.',ben:'راجع صفات المفلحين السبع، فإن وجدتها فأبشر، وإن فقدتها فاسعَ إليها.'},
  {ref:'النور: ٣١',surah:24,ayah:31,t:'وَقُل لِّلْمُؤْمِنَاتِ يَغْضُضْنَ مِنْ أَبْصَارِهِنَّ وَيَحْفَظْنَ فُرُوجَهُنَّ',ta:'أمر المؤمنات بغض البصر وحفظ الفرج، وبعدم إبداء زينتهن إلا لمن ذكر الله من المحارم، فالعفة أساس صلاح المجتمع.',ben:'الغض من البصر حصن للقلب، فاحفظ بصرك يحفظ الله قلبك.'},
  {ref:'النساء: ٢٩',surah:4,ayah:29,t:'يَا أَيُّهَا الَّذِينَ آمَنُوا لَا تَأْكُلُوا أَمْوَالَكُم بَيْنَكُم بِالْبَاطِلِ إِلَّا أَن تَكُونَ تِجَارَةً عَن تَرَاضٍ',ta:'نهي عن أكل المال بالباطل (الربا، الغش، السرقة)، وإباحة التجارة عن تراضٍ. فكسب المال يجب أن يكون حلالاً.',ben:'تأكد من حلية كل درهم يدخل جيبك، فهو غذاء جسدك وروحك.'},
  {ref:'البقرة: ٢٦٣',surah:2,ayah:263,t:'قَوْلٌ مَّعْرُوفٌ وَمَغْفِرَةٌ خَيْرٌ مِّن صَدَقَةٍ يَتْبَعُهَا أَذًى',ta:'بيان أن القول المعروف (الرد الجميل) والمغفرة (عفو عن الإساءة) خير من صدقة يتبعها أذى. فالنية في الصدقة مهمة.',ben:'إذا أعطيت، فلا تتبع عطاءك بمنّ، فهذا يُفسد الأجر.'},
  {ref:'آل عمران: ٩٢',surah:3,ayah:92,t:'لَن تَنَالُوا الْبِرَّ حَتَّىٰ تُنفِقُوا مِمَّا تُحِبُّونَ',ta:'بيان أن البر لا يُنال إلا بالإنفاق من المحبوب، فالمؤمن ينفق من أطيب ما يملك، لا من أردأه.',ben:'تصدق بشيء تحبه، تجد لذة الصدقة وحلاوة البر.'},
  {ref:'النساء: ١١٤',surah:4,ayah:114,t:'لَا خَيْرَ فِي كَثِيرٍ مِّن نَّجْوَاهُمْ إِلَّا مَنْ أَمَرَ بِصَدَقَةٍ أَوْ مَعْرُوفٍ أَوْ إِصْلَاحٍ بَيْنَ النَّاسِ',ta:'بيان أن أكثر النجوى لا خير فيها، إلا ما كان أمراً بصدقة أو معروف أو إصلاح بين الناس. فهذه الثلاث هي خير ما يتناجى به.',ben:'قبل أن تتكلم في غيبة أحد، اسأل: هل في كلامي خير؟'},
  {ref:'المائدة: ٢',surah:5,ayah:2,t:'وَتَعَاوَنُوا عَلَى الْبِرِّ وَالتَّقْوَىٰ ۖ وَلَا تَعَاوَنُوا عَلَى الْإِثْمِ وَالْعُدْوَانِ',ta:'أمر بالتعاون على البر والتقوى، ونهي عن التعاون على الإثم والعدوان. فالمؤمن عونٌ لأخيه على الخير لا على الشر.',ben:'كن عوناً لإخوانك على الطاعة، فإن أعنتهم فلك مثل أجرهم.'}
];

