const HADITH_POOL = [
  {text:'إنما الأعمالُ بالنياتِ، وإنما لكلِّ امرئٍ ما نوى، فمن كانت هجرتُه إلى الله ورسوله فهجرتُه إلى الله ورسوله، ومن كانت هجرتُه إلى دنيا يُصيبها أو امرأةٍ ينكحها فهجرتُه إلى ما هاجر إليه',isnad:'عن عمر بن الخطاب رضي الله عنه',src:['رواه البخاري','ومسلم','أول حديث في صحيح البخاري'],expl:'هذا الحديث أصلٌ في إخلاص النية، فكل عملٍ لا يُقصد به وجه الله فلا أجر فيه. النية هي روح العمل، وقد بدأ البخاري صحيحه به؛ لأهميته. النية تميّز العبادة عن العادة، والعبادات بعضها عن بعض. فالصلاة بالنية، والصوم بالنية، وكذلك سائر الأعمال. ومن نوى بعمله الدنيا، فلا نصيب له في الآخرة من ذلك العمل.',ben:'راجع نيتك قبل كل عمل: لماذا تفعل ما تفعل؟'},
  {text:'الإسلامُ أن تشهدَ أن لا إله إلا الله وأن محمداً رسولُ الله، وتُقيمَ الصلاة، وتُؤتيَ الزكاة، وتصومَ رمضان، وتحُجَّ البيتَ إن استطعتَ إليه سبيلا. والإيمانُ أن تؤمنَ بالله وملائكتِه وكتبِه ورسله واليوم الآخر، وتؤمنَ بالقدر خيره وشره',isnad:'عن عمر بن الخطاب رضي الله عنه',src:['رواه مسلم','حديث جبريل'],expl:'هذا حديث جامع لأركان الإسلام والإيمان والإحسان، يُعرف بحديث جبريل، فقد جاء جبريل عليه السلام يعلم الصحابة دينهم. الإسلام خمسة أركان عملية، والإيمان ستة أركان قلبية، والإحسان أن تعبد الله كأنك تراه. هذه أصول الدين التي يجب على كل مسلم معرفتها.',ben:'احفظ أركان دينك، فهي أساس إسلامك وإيمانك.'},
  {text:'من حُسنِ إسلامِ المرءِ تركُه ما لا يعنيه',isnad:'عن أبي هريرة رضي الله عنه',src:['رواه الترمذي','حسن'],expl:'هذا الحديث أصلٌ في حفظ اللسان والجوارح عما لا فائدة فيه. فالمسلم الحقيقي لا يتدخل فيما لا يعنيه، ولا يتابع ما لا طائل منه، فيسلم دينه ووقته. وترك ما لا يعني يشمل: الكلام فيما لا فائدة فيه، والاطلاع على ما لا يحتاجه، ومتابعة أخبار الناس. ومن حفظ وقته بطاعة الله فقد حَسُن إسلامه.',ben:'قبل أي كلام أو فعل، اسأل: هل هذا يعنيني؟'},
  {text:'المسلمُ من سلم المسلمون من لسانِه ويدِه، والمهاجرُ من هجر ما نهى الله عنه',isnad:'عن عبد الله بن عمرو رضي الله عنهما',src:['رواه البخاري','ومسلم'],expl:'تعريف جامع للمسلم الحقيقي بأنه من لا يؤذي المسلمين بلسانه ولا بيده، فالعبرة بالعمل لا بالاسم. والمهاجر الحقيقي من هجر المعاصي والذنوب، فالهجرة الحقيقية هجرة القلب من الشرك والمعاصي إلى التوحيد والطاعة. فالإسلام ليس دعوى بل عمل، والهجرة ليست انتقالاً جغرافياً بل تغييراً قلبياً.',ben:'احفظ لسانك عن الناس، وقلبك عن المعاصي، تكن مسلماً مهاجراً.'},
  {text:'لا يؤمنُ أحدُكم حتى يُحبَّ لأخيهِ ما يُحبُّ لنفسِه',isnad:'عن أنس بن مالك رضي الله عنه',src:['رواه البخاري','ومسلم'],expl:'هذا الحديث ميزان للأخلاق الاجتماعية، فلا يكتمل إيمان المرء إلا إذا أحب لأخيه المسلم مثل ما يحب لنفسه من الخير. وهذا يشمل: محبة النفع، وكرة الضر. فمن كره لأخيه ما يكره لنفسه فقد أكمل إيمانه. قال العلماء: هذا الحديث أصل في الوصاية وحسن الخلق والتعامل.',ben:'تأمل: ما الذي تحبه لنفسك؟ أحبه لأخيك المسلم.'},
  {text:'من كان يؤمنُ بالله واليوم الآخر فليقل خيراً أو ليصمت، ومن كان يؤمن بالله واليوم الآخر فليكرم جارَه، ومن كان يؤمن بالله واليوم الآخر فليكرم ضيفَه',isnad:'عن أبي هريرة رضي الله عنه',src:['رواه البخاري','ومسلم'],expl:'ثلاث وصايا نبوية مربوطة بالإيمان: حفظ اللسان (قول خير أو صمت)، وإكرام الجار، وإكرام الضيف. فاللسان أعظم ما يُبتلى به الإنسان، والجار له حق، والضيف له حق. من أراد كمال إيمانه فليحفظ هذه الثلاث.',ben:'اليوم: صممتُ عن الشر، أكرمتُ جاري، رحبتُ بضيفي.'},
  {text:'إن الله كتب الإحسانَ على كل شيء، فإذا قتلتم فأحسنوا القِتلة، وإذا ذبحتم فأحسنوا الذِّبح، ولْيُحِدَّ أحدُكم شفرتَه ولْيُرِحْ ذبيحتَه',isnad:'عن شداد بن أوس رضي الله عنه',src:['رواه مسلم'],expl:'الإحسان مطلوب في كل شيء، حتى في القتل والذبح. فالإسلام دين الرحمة، يأمر بإحسان القتل (أي بالطريقة السريعة التي لا تعذب)، وإحسان الذبح بإحداد الشفرة وإراحة الذبيحة. فكيف بغير القتل والذبح؟ فالإحسان مطلوب في معاملة الخلق أجمعين، حتى الحيوان.',ben:'الإحسان في كل شيء: في كلامك، عملك، تعاملك، حتى مع الحيوان.'},
  {text:'اتقِ الله حيثما كنت، وأتبع السيئةَ الحسنةَ تَمحُها، وخالقِ الناسَ بخُلقٍ حسن',isnad:'عن أبي ذر ومعاذ بن جبل رضي الله عنهما',src:['رواه الترمذي','حسن'],expl:'ثلاث وصايا جامعة: تقوى الله في السر والعلن، ومحو السيئة بالحسنة (التوبة والاستغفار)، وحسن الخلق مع الناس. فالوصية الأولى بين العبد وربه، والثانية بين العبد ونفسه، والثالثة بين العبد والناس. جامعة لحقوق الله وحقوق النفس وحقوق العباد.',ben:'حافظ على تقواك في خلوطك، وامحُ خطيئتك بطاعة، وعامل الناس بأخلاق.'},
  {text:'الدِّينُ النصيحةُ. قلنا: لمن؟ قال: لله ولكتابه ولرسوله ولأئمة المسلمين وعامتهم',isnad:'عن تميم الداري رضي الله عنه',src:['رواه مسلم'],expl:'النصيحة هي جماع الدين، لله بإفراده بالعبادة، ولكتابه بتلاوته والعمل به، ولرسوله باتباع سنته، ولأئمة المسلمين بإعانتهم على الحق، وعامة المسلمين بإرشادهم ودعوتهم للخير. فالنصيحة ليست اطلاعاً على العيوب، بل إرادة الخير للمنصوح.',ben:'انصح نفسك أولاً، ثم أهلك، ثم من تستطيع من المسلمين.'},
  {text:'من دلَّ على خيرٍ فله مثلُ أجرِ فاعلِه',isnad:'عن أبي مسعود الأنصاري رضي الله عنه',src:['رواه مسلم'],expl:'من أرشد إلى خير، سواء فعله هو أو غيره، فله مثل أجر من فعله، لأنه سبب في حصوله. فباب الدلالة على الخير مفتوح، سواء بدعوة، أو إرشاد، أو نشر علم، أو مساعدة محتاج. ومن أعظم أبواب الخير: تعليم الناس الخير.',ben:'شارك آية أو حديثاً أو فائدة، فلك مثل أجر من عمل بها.'},
  {text:'المؤمنُ المؤمنُ كالبناءِ يَشدُّ بعضُه بعضاً، وشبّك بين أصابعه',isnad:'عن أبي موسى الأشعري رضي الله عنه',src:['رواه البخاري','ومسلم'],expl:'تشبيه المؤمنين بالبناء المرصوص الذي يشد بعضه بعضاً، فالمؤمن لا يستغني عن أخيه، وكل واحد منهم يسند الآخر. فالمجتمع المسلم كالجسد الواحد، إذا اشتكى منه عضو تداعى له سائر الجسد. وفي هذا الحث على التعاون والتكافل.',ben:'كن جزءاً من بناء المجتمع، أَعن إخوانك يَشدّك الله.'},
  {text:'مثلُ ما بعثني الله به من الهدى والعلم كمثلِ الغيثِ الكثير أصاب أرضاً، فكان منها نَقيَّةٌ قَبِلَتِ الماءَ فأنبتت الكلأ والعشب الكثير',isnad:'عن أبي موسى الأشعري رضي الله عنه',src:['رواه البخاري','ومسلم'],expl:'تشبيه العلم والهدى بالغيث، والقلوب بالأرض. فمن القلوب ما يقبل العلم فينبت خيراً، ومنها ما يحفظ العلم ليفيده غيره، ومنها ما لا يقبل. فالعبرة بقبول القلب للعلم وعمله به. والمؤمن العالم أنفع للمجتمع من المؤمن العابد فقط.',ben:'اجعل قلبك أرضاً طيبة للعلم، تسمع، تفهم، تعمل، تُعلّم.'},
  {text:'حقُّ المسلمِ على المسلمِ خمسٌ: ردُّ السلام، عيادةُ المريض، اتباعُ الجنائز، إجابةُ الدعوة، تشميتُ العاطس',isnad:'عن أبي هريرة رضي الله عنه',src:['رواه البخاري','ومسلم'],expl:'خمس حقوق أصلية بين المسلمين: رد السلام (إفشاء الأمن)، عيادة المريض (التكافل)، اتباع الجنائز (التعاون على البر)، إجابة الدعوة (إكرام الداعي)، تشميت العاطس (الذكر المشترك). وهي حقوق فرض كفاية أو عين، تجمع المجتمع وتقوي روابطه.',ben:'احفظ حقوق إخوانك الخمس، تطبق سنّة نبيك.'},
  {text:'لا تحاسدوا ولا تناجشوا ولا تباغضوا ولا تدابروا ولا يبع بعضُكم على بيع بعض، وكونوا عبادَ الله إخواناً، المسلمُ أخو المسلم',isnad:'عن أبي هريرة رضي الله عنه',src:['رواه مسلم'],expl:'نهي عن خمس آفات اجتماعية: الحسد (تمني زوال النعمة)، النجش (الزيادة في السعر للخداع)، البغضاء، التدبير (القطيعة)، البيع على بيع الأخ. وأمر بالأخوة. فالمجتمع المسلم مجتمع محبة وتكافل، لا تنافس وعداوة.',ben:'طهّر قلبك من الحسد، ولسانك من الغيبة، ويدك من الغش.'},
  {text:'من غدا إلى المسجدِ أو راح أعدَّ الله له في الجنة نُزُلاً كلما غدا أو راح',isnad:'عن أبي هريرة رضي الله عنه',src:['رواه البخاري','ومسلم'],expl:'وعد لمن يذهب إلى المسجد للصلاة بأن يُعدّ الله له نُزلاً (ضيافة) في الجنة في كل مرة يذهب فيها. فالمشي إلى المسجد تكفير للذنوب، وضيافة في الجنة. فلا تترك الصلاة في جماعة إلا لعذر، فأجرها عظيم.',ben:'اجعل لك ورداً يومياً من المسجد، ولو لصلاة واحدة.'},
  {text:'من نفَّسَ عن مؤمنٍ كربةً من كُرَبِ الدنيا نفَّس الله عنه كربةً من كُرَبِ يوم القيامة، واللهُ في عونِ العبدِ ما كان العبدُ في عونِ أخيه',isnad:'عن أبي هريرة رضي الله عنه',src:['رواه مسلم'],expl:'الحث على تفريج الكرب، فمن أعان مسلماً في دنيا أعانه الله في الآخرة. والله يعين العبد ما دام العبد يعين أخاه. وتفريج الكرب بأنواع: بقضاء دين، أو جاه، أو نصيحة، أو دعاء، أو إرشاد، أو مال.',ben:'افعل اليوم خيراً: أعن محتاجاً، أو فرّج كربةً، تكن في عون الله.'},
  {text:'من سلك طريقاً يلتمسُ فيه علماً سهّل الله له به طريقاً إلى الجنة',isnad:'عن أبي هريرة رضي الله عنه',src:['رواه مسلم'],expl:'الحث على طلب العلم الشرعي، فمن سلك طريقاً يطلب العلم فُتح له باب إلى الجنة. وطلب العلم عبادة، ومدارسته ذكر، والبحث عنه جهاد. فاحرص على تعلم ما يقربك إلى الله، ولو آية أو حديث.',ben:'اجعل لك كل يوم نصيباً من العلم الشرعي.'},
  {text:'إذا مات الإنسانُ انقطع عملُه إلا من ثلاث: صدقةٍ جارية، أو علمٍ يُنتفعُ به، أو ولدٍ صالحٍ يدعو له',isnad:'عن أبي هريرة رضي الله عنه',src:['رواه مسلم'],expl:'بيان أن عمل الميت ينقطع بموته، إلا ثلاثة: صدقة جارية (كبناء مسجد أو بئر)، أو علم ينتفع به (كتاب، تلميذ، فتوى)، أو ولد صالح يدعو له. فمن أراد أن يستمر أجره بعد موته فليحرص على هذه الثلاث.',ben:'استثمر لموتك: علّم، أو تَصدّق، أو احفظ ولدك على الصلاح.'},
  {text:'ما نقصتْ صدقةٌ من مال، وما زاد الله عبداً بعفوٍ إلا عِزّاً، وما تواضع أحدٌ لله إلا رفعه الله',isnad:'عن أبي هريرة رضي الله عنه',src:['رواه مسلم'],expl:'ثلاث بشارات: الصدقة لا تنقص المال بل تزيده وتباركه، والعفو عن الناس يزيد العبد عِزّاً لا ذلاً، والتواضع لله يرفع العبد. فالأخلاق الحميدة تزيد العبد خيراً في الدنيا والآخرة، فلا تظن أن العطاء ينقص، بل يزيد.',ben:'تصدّق، اعفُ، تواضع، تكن في زيادة دائمة.'},
  {text:'من لا يَرحمُ الناسَ لا يَرحمه الله',isnad:'عن جرير بن عبد الله رضي الله عنه',src:['رواه البخاري','ومسلم'],expl:'الحث على الرحمة بالخلق، فمن لا يرحم الناس لا ينال رحمة الله. والرحمة تشمل: الصغار، الكبار، الفقراء، الضعفاء،甚至 الحيوان. فالقلب القاسي محروم من رحمة الله، والقلب الرحيم موضع رحمته.',ben:'ارحم من حولك: طفلاً، ضعيفاً، فقيراً، حتى حيواناً، يرحمك الله.'},
  {text:'المُسلمُ أخو المسلم، لا يَظلمه ولا يُسلِمه، ومن كان في حاجةِ أخيه كان الله في حاجته، ومن فرَّج عن مسلمٍ كربةً فرَّج الله عنه كربةً من كُرَبِ يوم القيامة',isnad:'عن ابن عمر رضي الله عنهما',src:['رواه البخاري','ومسلم'],expl:'تأكيد على أخوة المسلمين: لا ظلم بينهم، ولا تسليم بعضهم لبعض. ومن قضى حاجة أخيه قضى الله حاجته. فالمسلم عونٌ لأخيه، لا متفرج عليه. وقضاء الحوائج من أعظم العبادات.',ben:'اسأل عن إخوانك: من يحتاج مساعدتي اليوم؟'},
  {text:'بَدأَ الإسلامُ غريباً، وسيعودُ كما بدأ غريباً، فطُوبى للغرباء',isnad:'عن أبي هريرة رضي الله عنه',src:['رواه مسلم'],expl:'نبوة بأن الإسلام بدأ غريباً (قلة أهله) وسيعود غريباً (قلّ المتمسكون به)، فطوبى للغرباء الذين يتمسكون بالحق عند فساد الناس. والغربة: إما غربة في الزمان (قلة المتمسكين)، أو في المكان (المسلم في بلد الكفار)، أو في الحال (التمسك عند الفتن).',ben:'اثبت على دينك وإن قلَّ أهله، فطوبى للغرباء.'},
  {text:'الكَيِّسُ من دانَ نفسَه وعَمِلَ لما بعد الموت، والعاجزُ من أتبعَ نفسَه هواها وتمنّى على الله',isnad:'عن شداد بن أوس رضي الله عنه',src:['رواه الترمذي','حسن'],expl:'الكيس (العاقل) من حاسب نفسه في الدنيا وعمل للآخرة، والعاجز من اتبع هواه وتمنى رحمة الله بلا عمل. فالمؤمن يحاسب نفسه قبل أن يُحاسب، ويزن أعماله قبل أن تُوزن. والتمني بلا عمل لا يُغني.',ben:'حاسب نفسك كل ليلة: ماذا عملت اليوم؟ وماذا تريد أن تعمل غداً؟'},
  {text:'ارحموا من في الأرض يَرحمْكم من في السماء',isnad:'عن عبد الله بن عمرو رضي الله عنهما',src:['رواه الترمذي','صححه الألباني'],expl:'الحث على الرحمة بجميع من في الأرض، فإن رحمة الله تنزل على الرحماء. والرحمة تشمل: الناس، الحيوان، الطير، حتى الجماد بالرفق. فمن رحم الخلق رحمه الخالق، ومن قسا قسا الله عليه.',ben:'ابدأ بالرفق في بيتك، مع أهلك وأولادك وحيواناتك.'},
  {text:'الطهورُ شطرُ الإيمان، والحمدُ لله تملأُ الميزان، وسبحان الله والحمدُ لله تملآنِ ما بين السماء والأرض',isnad:'عن أبي مالك الأشعري رضي الله عنه',src:['رواه مسلم'],expl:'الطهارة شطر الإيمان (نصفه) لأنها شرط لصلاة وهي عمود الدين. والحمد لله تملأ الميزان لكثرة ثوابها، وسبحان الله والحمد لله تملآن ما بين السماء والأرض لعظيم أجرهما. فالأذكار ثقيلة في الميزان.',ben:'احفظ وردك من الأذكار، فهو يملأ ميزانك يوم القيامة.'},
  {text:'أحبُّ الأعمالِ إلى الله أدومُها وإن قلَّ',isnad:'عن عائشة رضي الله عنها',src:['رواه البخاري','ومسلم'],expl:'أحب الأعمال إلى الله ما داوم عليه العبد وإن كان قليلاً، لأن المداومة تدل على الإخلاص وتُحدث أثراً، بخلاف الكثير المنقطع. فالقليل الدائم خير من الكثير المنقطع. فاحرص على عمل صالح يومي ولو كان يسيراً، كركعتين، أو وِرد قرآن، أو تسبيح.',ben:'اجعل لك أعمالاً صغيرة دائمة، أحب إلى الله من أعمال كبيرة منقطعة.'},
  {text:'من قال لا إله إلا الله وحده لا شريك له، له الملك وله الحمد وهو على كل شيء قدير، في يومٍ مائة مرة، كانت له عدلَ عشرِ رقاب، وكُتبت له مائةُ حسنة، ومُحيت عنه مائةُ سيئة',isnad:'عن أبي هريرة رضي الله عنه',src:['رواه البخاري','ومسلم'],expl:'فضل الذكر العظيم، فمن قال هذا الذكر مائة مرة في يوم فله أجر عتق عشر رقاب، ومائة حسنة، ومحى عنه مائة سيئة، وكان في حرز من الشيطان. فالأذكار كنز لا يُقدَّر بثمن، ينبغي للمسلم أن يحافظ عليها.',ben:'احفظ هذا الذكر، وردّده مائة مرة يومياً، تكن في حرز من الشيطان.'},
  {text:'ما من أحدٍ يتوضأ فيُحسن الوضوء ثم يقول: أشهد أن لا إله إلا الله وحده لا شريك له وأشهد أن محمداً عبده ورسوله، إلا فُتحت له أبواب الجنة الثمانية يدخل من أيها شاء',isnad:'عن عمر بن الخطاب رضي الله عنه',src:['رواه مسلم'],expl:'فضل إتمام الوضوء والإشهاد بعده، فُتحت له أبواب الجنة الثمانية. فالوضوء طهارة من الحدث ونظافة من الذنوب، والشهادة بعده تفتح أبواب الرحمة. فاحرص على هذا الذكر بعد كل وضوء.',ben:'بعد كل وضوء، قل الشهادتين بهذا اللفظ، تُفتح لك أبواب الجنة.'},
  {text:'من صلى عليَّ صلاةً صلى الله عليه بها عشراً',isnad:'عن أبي هريرة رضي الله عنه',src:['رواه مسلم'],expl:'الحث على الإكثار من الصلاة على النبي ﷺ، فمن صلى عليه مرة صلى الله عليه بها عشراً، والصلاة من الله رحمته، ومن الملائكة استغفار، ومن الناس دعاء. فأكثروا من الصلاة عليه في كل حين، خصوصاً يوم الجمعة.',ben:'اجعل لك ورداً: اللهم صلِّ على محمد، مائة مرة يومياً.'},
  {text:'من استغفرَ اللهَ ودَمَعَتْ عيناه دخل الجنة',isnad:'عن ابن عمر رضي الله عنهما',src:['رواه الطبراني','حسن'],expl:'فضل الاستغفار مع البكاء من خشية الله، فمن استغفر بقلبٍ حاضر وبكى، فله الجنة. فالبكاء من خشية الله يُطفئ نار الذنوب، ويُرقق القلب، ويُجلب الرحمة. فاحرص على الاستغفار بخشوع، واطلب من الله أن يرقق قلبك.',ben:'استغفر الله بقلبك قبل لسانك، وابكِ على ذنبك، تُطفئ نار الذنوب.'},
  {text:'ألا وإنَّ في الجسدِ مُضغةً إذا صَلَحَت صَلَحَ الجسدُ كله، وإذا فَسَدَت فَسَدَ الجسدُ كله، ألا وهي القلب',isnad:'عن النعمان بن بشير رضي الله عنه',src:['رواه البخاري','ومسلم'],expl:'بيان أن صلاح الجسد كله بصلاح القلب، وفساده بفساده. فالقلب ملك الأعضاء، وإليه ترجع الأعمال. فأصلح قلبك تصلح جوارحك. وإصلاح القلب يكون بالإيمان والذكر والتوبة ومجالسة الصالحين.',ben:'اعرض قلبك على الله: هل هو سليم من الحسد والكبر والشرك؟'},
  {text:'مَن قال رضيتُ بالله رباً، وبالإسلام ديناً، وبمحمدٍ نبياً، وجبت له الجنة',isnad:'عن أبي سعيد الخدري رضي الله عنه',src:['رواه أبو داود','والترمذي','حسن'],expl:'فضل الرضا بالله رباً، وبالإسلام ديناً، وبمحمد ﷺ نبياً، فمن قال ذلك ثلاثاً صباحاً ومساءً وجبت له الجنة. فالرضا بالله يُثمر الطمأنينة، والرضا بالإسلام يُثمر الالتزام، والرضا بالنبي يُثمر الاتباع.',ben:'قلها ثلاثاً صباحاً ومساءً، تكن من أهل الجنة بإذن الله.'},
  {text:'إن في الجنة غُرفاً يُرى ظاهرُها من باطنها، وباطنها من ظاهرها، أعدَّها الله لمن أطعم الطعام، وأفشى السلام، وصلى بالليل والناس نيام',isnad:'عن أبي مالك الأشعري رضي الله عنه',src:['رواه ابن حبان','صححه الألباني'],expl:'ثلاث أعمال تُدخل صاحبها الغرف العالية في الجنة: إطعام الطعام (الكرم)، وإفشاء السلام (المحبة)، وصلاة الليل (الخلوة بالله). فاجمع هذه الثلاث في يومك تكن من أهل الغرف. وصلاة الليل من أفضل التطوعات.',ben:'اقم الليل ولو ركعتين، وأطعم، وأفش السلام، تكن من أهل الغرف.'}
];

